const triggerData = $('Execute Workflow Trigger').first().json;
const profile = $('Get User Profile').first().json;
const prevPlan = $('Get Previous Exercise Plan').all();
const previousPlan = prevPlan.length > 0 ? prevPlan[0].json.plan_json : null;

const prompt = `Eres un entrenador personal experto. Crea un plan de entrenamiento semanal detallado y personalizado.

Perfil del usuario:
- Nivel de fitness: ${profile.fitness_level || 'principiante'}
- Días de entrenamiento por semana: ${profile.training_days_per_week || 3}
- Equipamiento disponible: ${profile.available_equipment || 'sin equipamiento'}
- Lesiones o restricciones: ${profile.injuries || 'ninguna'}
- Objetivo principal: ${profile.goal || 'mejorar condición física general'}
- Edad: ${profile.age || 'no especificada'}
- Peso actual: ${profile.current_weight_kg || 'no especificado'} kg
- Altura: ${profile.height_cm || 'no especificada'} cm

${previousPlan ? 'Plan anterior (para evitar repetición y asegurar progresión):\n' + JSON.stringify(previousPlan, null, 2) : 'Es el primer plan del usuario.'}

Devuelve el plan en formato JSON con la siguiente estructura:
{
  "week_summary": "descripción breve del plan",
  "days": [
    {
      "day": "Lunes",
      "focus": "Tren superior",
      "exercises": [
        {
          "name": "nombre del ejercicio",
          "sets": 3,
          "reps": "10-12",
          "rest": "60 segundos",
          "notes": "indicaciones técnicas"
        }
      ],
      "duration_minutes": 45,
      "warmup": "descripción del calentamiento",
      "cooldown": "descripción del enfriamiento"
    }
  ],
  "weekly_tips": ["consejo 1", "consejo 2"]
}`;

return [{
  json: {
    userId: triggerData.userId,
    requestType: triggerData.requestType,
    fitnessLevel: profile.fitness_level,
    prompt,
    profile
  }
}];

const triggerData = $('Execute Workflow Trigger').first().json;
const profile = $('Get User Profile').first().json;
const rawContent = $input.first().json.text || '';

let planJson;
try {
  // Extract JSON from markdown code blocks if present
  const jsonMatch = rawContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  const jsonStr = jsonMatch ? jsonMatch[1] : rawContent;
  planJson = JSON.parse(jsonStr.trim());
} catch (e) {
  planJson = { raw: rawContent, parse_error: e.message };
}

const now = new Date();
const weekNumber = Math.ceil((now - new Date(now.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000));

return [{
  json: {
    userId: triggerData.userId,
    planJson,
    weekNumber,
    year: now.getFullYear(),
    fitnessLevel: profile.fitness_level || 'beginner'
  }
}];

const data = $('Parse Workout Plan').first().json;
const plan = data.planJson;

let message = '💪 *Tu Plan de Entrenamiento Semanal*\n\n';

if (plan.week_summary) {
  message += '📋 ' + plan.week_summary + '\n\n';
}

if (plan.days && Array.isArray(plan.days)) {
  for (const day of plan.days) {
    message += '━━━━━━━━━━━━━━\n';
    message += '🗓 *' + day.day + '* — ' + day.focus + '\n';
    message += '⏱ Duración: ' + (day.duration_minutes || '?') + ' min\n\n';

    if (day.exercises && Array.isArray(day.exercises)) {
      for (const ex of day.exercises) {
        message += '• *' + ex.name + '*: ' + ex.sets + ' series x ' + ex.reps + ' reps';
        if (ex.rest) message += ' (descanso: ' + ex.rest + ')';
        message += '\n';
        if (ex.notes) message += '  _' + ex.notes + '_\n';
      }
    }
    message += '\n';
  }
}

if (plan.weekly_tips && Array.isArray(plan.weekly_tips)) {
  message += '💡 *Consejos de la semana:*\n';
  for (const tip of plan.weekly_tips) {
    message += '• ' + tip + '\n';
  }
}

return [{ json: { message, planJson: plan } }];

